package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithCommentMarker() {
        CSVFormat original = CSVFormat.DEFAULT;
        char commentChar = '#';

        CSVFormat updated = original.withCommentMarker(commentChar);

        assertNotNull(updated);
        assertNotSame(original, updated);
        assertEquals(Character.valueOf(commentChar), updated.getCommentMarker());

        // Also test with a different comment char
        char anotherChar = '!';
        CSVFormat updated2 = updated.withCommentMarker(anotherChar);
        assertEquals(Character.valueOf(anotherChar), updated2.getCommentMarker());

        // Test with null comment character (via withCommentMarker(Character))
        CSVFormat updatedNull = updated.withCommentMarker((Character) null);
        assertNull(updatedNull.getCommentMarker());
    }
}
